args.sparql:
SELECT ?opponentTeam ?seasonRecord WHERE {
  ?match wdt:P550 wd:Q17515651 ;
         (wdt:P1295|wdt:P1296) wd:Q17515651 ;
         (wdt:P1473|wdt:P1474) ?harvardScore ;
         (wdt:P1473|wdt:P1474) ?opponentScore .
  FILTER(ABS(?opponentScore - ?harvardScore) = 7)
  ?match wdt:P1295 ?team1 ;
         wdt:P1296 ?team2 .
  VALUES ?targetTeam { wd:Q17515651 }
  FILTER(?targetTeam = ?team1 || ?targetTeam = ?team2)
  FILTER(?targetTeam = ?team1 || ?targetTeam = ?team2)
  BIND(IF(?team1 = wd:Q17515651, ?team2, ?team1) AS ?opponentTeam)
  ?opponentSeason wdt:P550 wd:Q17515651 ;
                 wdt:P1948 ?opponentTeam ;
                 wdt:P2441 ?seasonRecord .
  FILTER(lang(?seasonRecord) = 'en')
}

SELECT ?opponentTeam ?record WHERE {
  ?match wdt:P550 wd:Q17515651 ;
         (wdt:P1295|wdt:P1296) wd:Q17515651 ;
         wdt:P1473 ?harvardScore ;
         wdt:P1474 ?opponentScore .
  FILTER(?opponentScore - ?harvardScore = 7)
  BIND(IF(?match wdt:P1295 wd:Q17515651, ?match wdt:P1296, ?match wdt:P1295) AS ?opponentTeam)
  ?opponentSeason wdt:P1343 ?opponentTeam ;
                 wdt:P487 ?record .
  FILTER(LANG(?record) = 'en')
}

