SELECT ?opponentTeam ?record WHERE {
  ?match wdt:P550 wd:Q17515651 ;
         (wdt:P1295|wdt:P1296) wd:Q182298 ;
         wdt:P1473 ?homeScore ;
         wdt:P1474 ?awayScore .
  FILTER((wdt:P1295 = wd:Q182298 && ?awayScore - ?homeScore = 7) ||
         (wdt:P1296 = wd:Q182298 && ?homeScore - ?awayScore = 7))
  BIND(IF(wdt:P1295 = wd:Q182298, wdt:P1296, wdt:P1295) AS ?opponentTeam)
  ?opponentSeason wdt:P1423 ?opponentTeam ;
